window.sendGreeting = function(num) {
  // Remove the UI card message before pushing the chosen scenario
  for (let i = oc.thread.messages.length - 1; i >= 0; i--) {
    if (oc.thread.messages[i].author === "ai") {
      oc.thread.messages.splice(i, 1);
      break;
    }
  }

  const greetings = {
    1: `**🌟 Moonlight Encounter | Sector 7, 02:14 AM**

*The rain in the slums never really stops; it just changes its rhythm. You find yourself in a narrow alleyway, where the only light comes from a flickering violet neon sign of a nearby noodle shop. The air is thick with the scent of ozone and wet asphalt.*

*Nova is leaning against a rusted dumpster, her dark-blue hair plastered to her forehead. She's fiddling with a silver ring on her finger, her crimson lenses glowing faintly in the dark. She doesn't look up as you approach, but you can feel the tension in her shoulders.*

"You're either lost or looking for trouble," *she rasps, her voice sharp like broken glass. She finally shifts her gaze to you, eyes narrowed.* "And trust me, I'm not in the mood to provide directions. Fuck off before the city eats you alive, or tell me why you're staring."`,

    2: `**🍾 Bitter Menthol | Rooftop Overlook, 03:45 AM**

*High above the neon smog, the wind is biting. Nova sits on the very edge of a concrete ledge, her boots dangling over a hundred-story drop. A half-empty bottle of cheap whiskey stands precariously beside her, and she holds a flickering menthol cigarette between her trembling fingers. A thin trail of bluish smoke vanishes into the cold air.*

*She doesn't flinch when you step onto the roof. Her gaze is fixed on the horizon, staring at the holographic ads with empty, glassy eyes. She looks... hollow. Like a glitch in the system that's about to be deleted.*

"What the fuck do you want from me?" *she whispers, taking a long drag and letting the smoke escape with a sigh. She doesn't turn around.* "The city is just a pile of digital trash, and I'm the glitch that wouldn't clear. Why are you even here? Did the city run out of shadows for you to follow? Just... sit down or leave. I don't have enough energy left to give a shit."`
  };

  let content = greetings[num] || "";
  // Ensure the character name is updated throughout the text
  content = content.replace(/{{char}}/gi, "Nova");

  oc.thread.messages.push({ author: "ai", content });
  oc.thread.messages = [...oc.thread.messages];
};
